<script setup lang="ts">
import type { Question, Option as QuestionOption } from '../utils/types'

interface Props {
  question: Question
  currentIndex: number
  selectedOption?: number  // 当前题目已选择的选项索引，-1表示未选择
}

const props = defineProps<Props>()

const baseUrl = import.meta.env.BASE_URL || '/ancient-test/'

const emit = defineEmits<{
  (e: 'select', optionIndex: number): void
  (e: 'goto-question', questionIndex: number): void
}>()

// 处理选项选择
const handleSelect = (optionIndex: number) => {
  emit('select', optionIndex)
}

// 繁体数字映射
const chineseNumbers = ['壹', '贰', '叁', '肆']

// 获取选项样式类
const getOptionClass = (_option: QuestionOption, optionIndex: number) => {
  if (props.selectedOption === optionIndex) {
    // 已选择的选项：绿色主题 #27ae60
    return 'group flex items-center space-x-3 p-4 rounded-2xl cursor-pointer transition-all selected-option'
  } else {
    // 未选择的选项
    return 'group flex items-center space-x-3 p-4 rounded-2xl cursor-pointer transition-all unselected-option'
  }
}

// 获取选项字母（壹、贰、叁、肆）
const getOptionLetter = (index: number) => {
  return chineseNumbers[index] || String(index + 1)
}
</script>

<template>
  <div class="card-with-texture rounded-3xl shadow-xuan-card p-6" :style="{ backgroundImage: `url('${baseUrl}images/paper_texture_01.png')` }">
    <!-- 题目标签 -->
    <div class="flex justify-between items-center mb-4">
      <span class="text-sm text-gray-400 tracking-widest">问题 {{ currentIndex + 1 }}</span>
      <span class="px-3 py-1 bg-gray-100 text-gray-500 text-xs rounded-full tracking-widest">单选</span>
    </div>

    <!-- 题目文本 -->
    <p class="text-lg font-medium text-[#2c3e50] mb-6 leading-relaxed tracking-widest">
      {{ question.text }}
    </p>

    <!-- 选项区域 -->
    <div class="space-y-3">
      <!-- 选项按钮 -->
      <div
        v-for="(option, index) in question.options"
        :key="option.id"
        @click="handleSelect(index)"
        :class="getOptionClass(option, index)"
      >
        <!-- 选项序号圆圈 -->
        <div
          class="option-circle w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium font-calligraphy"
          :class="selectedOption === index ? 'bg-white/20 text-white' : 'bg-gray-100 text-gray-400'"
        >
          {{ getOptionLetter(index) }}
        </div>

        <!-- 选项文本 -->
        <span class="flex-1 text-sm tracking-widest" :class="selectedOption === index ? 'text-white' : 'text-gray-600'">
          {{ option.text }}
        </span>

        <!-- 选中图标 -->
        <svg v-if="selectedOption === index" class="w-5 h-5 text-white" fill="currentColor" viewBox="0 0 20 20">
          <path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clip-rule="evenodd"/>
        </svg>
      </div>
    </div>

    <!-- 操作提示 -->
    <div class="mt-6 pt-4 border-t border-gray-200/50">
      <p class="text-sm text-gray-500 text-center tracking-widest">
        <span v-if="selectedOption === undefined || selectedOption < 0">
          请选择一个最符合你的选项
        </span>
        <span v-else>
          已选择，请点击其他选项可更改
        </span>
      </p>
    </div>
  </div>
</template>

