// 五行元素类型（英文，用于内部计算）
export type ElementType = 'metal' | 'wood' | 'water' | 'fire' | 'earth'

// 五行元素类型（中文，用于数据源）
export type ElementTypeCN = '金' | '木' | '水' | '火' | '土'

// 中文五行到英文五行的映射
export const ELEMENT_MAP: Record<ElementTypeCN, ElementType> = {
  '金': 'metal',
  '木': 'wood',
  '水': 'water',
  '火': 'fire',
  '土': 'earth'
}

// 英文五行到中文五行的映射
export const ELEMENT_MAP_REVERSE: Record<ElementType, ElementTypeCN> = {
  'metal': '金',
  'wood': '木',
  'water': '水',
  'fire': '火',
  'earth': '土'
}

// 中文五行权重对象（v1.1格式）
export interface ElementWeightsCN {
  金: number
  木: number
  水: number
  火: number
  土: number
}

// 英文五行权重对象（v1.1格式）
export interface ElementWeights {
  metal: number
  wood: number
  water: number
  fire: number
  earth: number
}

// 数据源选项（来自元贞的JSON数据 - v1.1格式）
export interface DataOption {
  text: string
  weights: ElementWeightsCN
}

// 数据源题目（来自元贞的JSON数据 - v1.1格式）
export interface DataQuestion {
  text: string
  options: DataOption[]
}

// 数据源身份信息（来自元贞的JSON数据 - v1.1格式）
export interface DataIdentityType {
  code: string
  name: string
  dimension: string
  description: string
  historical_figures: string
  personality_traits: string[]
  daily_practice: string
  self_cultivation: string
}

// v2.0 新类型定义 ============================================================

// v2.0 身份变体
export interface IdentityVariant {
  id: string
  code: string
  name: string
  category: string
  category_desc: string
  element: ElementTypeCN
  element_desc: string
  historical_figures: string
  core_description: string
  personality_traits: string[]
  daily_practice: string
  self_cultivation: string
  image_url?: string // 人物插画URL
}

// v2.0 选项 - 五行权重现在是数组格式 [金,木,水,火,土]
export interface OptionV2 {
  letter: string
  text: string
  五行权重: number[]  // [金,木,水,火,土]
  四维倾向文本: string
  原选项文本: string
}

// v2.0 题目
export interface QuestionV2 {
  number: number
  title: string
  question: string
  options: OptionV2[]
}

// v2.0 统计数据
export interface StatisticsV2 {
  total_identities: number
  total_questions: number
  total_options: number
  elements_distribution: Record<ElementTypeCN, number>
  identity_completeness: string
  question_completeness: string
  element_balance: string
}

// v2.0 数据源根对象
export interface DataSourceV2 {
  version: string
  description: string
  created_at: string
  created_by: string
  optimized_by: string
  note: string
  statistics: StatisticsV2
  identities: IdentityVariant[]
  questions: QuestionV2[]
}

// v1.1 数据源根对象（保持向后兼容）
export interface DataSource {
  identityTypes: DataIdentityType[]
  questions: DataQuestion[]
  metadata: {
    version: string
    description: string
    created_at: string
    note: string
  }
}

// 应用内部使用的测试选项（兼容v1.1和v2.0）
export interface Option {
  id: string
  text: string
  element: ElementType
  weights: ElementWeights  // 转换后的权重
  // v2.0 新增字段（可选）
  letter?: string
  fourDimensionText?: string  // 四维倾向文本
  originalText?: string       // 原选项文本
}

// 应用内部使用的测试题目
export interface Question {
  id: number
  text: string
  options: Option[]
  // v2.0 新增字段（可选）
  title?: string
  number?: number
}

// 应用内部使用的身份信息（扩展以支持v2.0）
export interface IdentityInfo {
  code: string
  name: string
  dimension: string
  description: string
  element: ElementType  // 主要五行属性（基于映射）
  traits: string[]      // 后续使用 personality_traits
  // v2.0 新增字段（可选）
  id?: string
  category?: string
  category_desc?: string
  element_desc?: string
  historical_figures?: string
  core_description?: string
  daily_practice?: string
  self_cultivation?: string
  image_url?: string // 人物插画URL
}

// 五行分数（英文）
export interface ElementScores {
  metal: number
  wood: number
  water: number
  fire: number
  earth: number
}

// 实用类型：数据源版本检测
export type DataSourceAny = DataSource | DataSourceV2

// 实用类型：版本检测结果
export interface VersionDetectionResult {
  version: 'v1.1' | 'v2.0'
  data: DataSourceAny
}