<script setup lang="ts">
import { ref, onMounted } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import ResultDisplay from '../components/ResultDisplay.vue'
import { loadData, getDataVersion } from '../utils/dataLoader'
import { jumpToMiniProgramWithIdentity } from '../utils/miniProgramJump'
import type { IdentityInfo, ElementScores } from '../utils/types'

const route = useRoute()
const router = useRouter()

// 加载数据
const { identities: loadedIdentities } = loadData()
const dataVersion = ref(getDataVersion())

// 响应式数据
const identity = ref<IdentityInfo | null>(null)
const elementScores = ref<ElementScores | null>(null)

// 跳转按钮 loading 状态
const isJumping = ref(false)

  // 从路由参数获取传递的数据
  onMounted(() => {
    const query = route.query

    // 如果有查询参数，使用它们（从QuizView跳转过来）
    if (query.id || query.code) {
      // 优先使用id查找，如果id不存在则使用code
      let foundIdentity = null
      if (query.id) {
        foundIdentity = loadedIdentities.find(item => item.id === query.id)
      }

      // 如果通过id没找到，或者没有id，尝试通过code查找
      if (!foundIdentity && query.code) {
        foundIdentity = loadedIdentities.find(item => item.code === query.code)
      }

      if (foundIdentity) {
        identity.value = foundIdentity
      } else {
        // 使用查询参数中的基本信息
        identity.value = {
          id: query.id as string || query.code as string,
          code: query.code as string,
          name: query.name as string || '未知身份',
          dimension: query.dimension as string || '',
          description: query.description as string || '无法获取描述信息',
          element: 'metal', // 默认值
          traits: []
        }
      }

      // 解析五行分数（格式：metal,wood,water,fire,earth）
      if (query.scores) {
        const scoresArr = (query.scores as string).split(',').map(Number)
        if (scoresArr.length === 5 && scoresArr.every(n => !isNaN(n))) {
          elementScores.value = {
            metal: scoresArr[0],
            wood: scoresArr[1],
            water: scoresArr[2],
            fire: scoresArr[3],
            earth: scoresArr[4]
          }
        }
      }
    } else {
      // 没有参数，跳回测试页面
      router.push('/quiz')
    }

  })








// 重新开始测试
const handleRestart = () => {
  router.push('/quiz')
}

// 查看详细分析
const handleViewAnalysis = () => {
  // 可以跳转到详细分析页面
  alert('详细分析功能将在后续版本中提供')
}

// 分享结果
const handleShare = () => {
  if (!identity.value) return

  const shareText = `我测出古代身份是【${identity.value.name}】！快来测试你的古代身份吧！`
  const shareUrl = window.location.origin + window.location.pathname

  if (navigator.share) {
    navigator.share({
      title: '古代身份测试结果',
      text: shareText,
      url: shareUrl
    }).catch(err => {
      console.log('分享取消:', err)
    })
  } else {
    // 复制到剪贴板
    navigator.clipboard.writeText(`${shareText} ${shareUrl}`)
      .then(() => {
        alert('结果已复制到剪贴板！')
      })
      .catch(err => {
        console.error('复制失败:', err)
        alert('请手动复制结果')
      })
  }
}

// 跳转到小程序了解更多五行知识
const handleJumpToMiniProgram = async () => {
  if (!identity.value) return

  isJumping.value = true

  try {
    // 传递身份信息和五行分数到云函数
    await jumpToMiniProgramWithIdentity(identity.value, elementScores.value)
  } catch (error) {
    console.error('跳转失败:', error)
    alert('跳转失败，请稍后重试')
  } finally {
    // 延迟重置状态，让跳转有机会发生
    setTimeout(() => {
      isJumping.value = false
    }, 3000)
  }
}


</script>

<template>
  <div class="min-h-screen flex flex-col items-center justify-center p-4 bg-gradient-to-b from-amber-50 to-orange-100">
    <!-- 头部 -->
    <header class="w-full max-w-2xl mb-8 text-center">
      <h1 class="text-3xl font-bold text-gray-800 mb-2">测试结果</h1>
      <p class="text-gray-600">探寻你隐藏的古代人格</p>
    </header>

    <!-- 结果展示 -->
    <div class="w-full max-w-2xl">
      <ResultDisplay
        v-if="identity"
        :identity="identity"
        :scores="elementScores"
        @restart="handleRestart"
        @view-analysis="handleViewAnalysis"
        @share="handleShare"
        @jump-to-miniprogram="handleJumpToMiniProgram"
      />

      <!-- 跳转加载状态提示 -->
      <div v-if="isJumping" class="mt-4 text-center">
        <div class="inline-flex items-center px-6 py-3 bg-amber-100 border border-amber-200 rounded-lg text-amber-700">
          <svg class="animate-spin -ml-1 mr-3 h-5 w-5 text-amber-500" fill="none" viewBox="0 0 24 24">
            <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
            <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          正在保存并跳转...
        </div>
      </div>
    </div>



    <!-- 底部信息 -->
    <footer class="w-full max-w-2xl mt-12 pt-6 border-t border-gray-200">
      <div class="text-center text-gray-500 text-sm">
        <p class="mb-2">古代身份测试 H5原型 v1.1 • 数据版本: {{ dataVersion }}</p>
        <p class="text-gray-400 text-xs">
          本测试基于五行理论和四维二元框架，结果仅供参考
        </p>
        <p class="text-gray-400 text-xs mt-1">
          测试数据持续优化中，欢迎提供反馈
        </p>
      </div>
    </footer>
  </div>
</template>

