<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import { useRouter } from 'vue-router'
import QuestionCard from '../components/QuestionCard.vue'
import { loadData } from '../utils/dataLoader'
import { getDataVersion } from '../utils/dataLoader'
import { determineIdentityAuto, calculateScores } from '../utils/calculateFiveElements'
import type { Question, IdentityInfo } from '../utils/types'

const router = useRouter()
const baseUrl = import.meta.env.BASE_URL || '/ancient-test/'

// 加载数据
const { questions: loadedQuestions, identities: loadedIdentities } = loadData()

// 数据版本
const dataVersion = ref(getDataVersion())

// 响应式数据
const questions = ref<Question[]>(loadedQuestions)
const identities = ref<IdentityInfo[]>(loadedIdentities)
const currentIndex = ref(0)
const selectedOptions = ref<number[]>(Array(loadedQuestions.length).fill(-1)) // 初始为-1表示未选择
const isComplete = computed(() => currentIndex.value >= questions.value.length)

const currentQuestion = computed(() => questions.value[currentIndex.value])

// 处理选项选择
const handleSelect = (optionIndex: number) => {
  // 记录当前题目的选择
  selectedOptions.value[currentIndex.value] = optionIndex

  // 如果还有下一题，继续
  if (currentIndex.value < questions.value.length - 1) {
    currentIndex.value++
  } else {
    // 所有题目完成，计算结果（自动检测v1.1或v2.0算法）
    const identity = determineIdentityAuto(questions.value, selectedOptions.value, identities.value)

    // 计算五行分数
    const scores = calculateScores(questions.value, selectedOptions.value)

    // 将分数转换为逗号分隔的字符串以便通过URL传递
    const scoresStr = `${scores.metal},${scores.wood},${scores.water},${scores.fire},${scores.earth}`

    // 跳转到结果页面，传递身份信息和分数
    router.push({
      path: '/result',
      query: {
        id: identity.id || identity.code, // v2.0使用id，v1.1回退到code
        code: identity.code,
        name: identity.name,
        dimension: identity.dimension,
        description: identity.description,
        scores: scoresStr
      }
    })
  }
}

// 处理上一题
const handlePrevious = () => {
  if (currentIndex.value > 0) {
    currentIndex.value--
  }
}

// 重新开始测试
const handleRestart = () => {
  currentIndex.value = 0
  selectedOptions.value = Array(loadedQuestions.length).fill(-1)
}

// 处理修改答案（返回特定题目）
const handleGotoQuestion = (index: number) => {
  currentIndex.value = index
}

// 计算进度百分比
const progressPercentage = computed(() => {
  const answeredCount = selectedOptions.value.filter(index => index >= 0).length
  return Math.round((answeredCount / questions.value.length) * 100)
})

// 初始化：确保有数据
onMounted(() => {
  console.log('古代身份测试H5原型 v2.9')
  console.log(`加载了 ${questions.value.length} 道题目`)
  console.log(`加载了 ${identities.value.length} 种身份类型`)
})
</script>

<template>
  <div class="quiz-container min-h-screen flex flex-col items-center relative overflow-hidden">
    <!-- 月白基础背景 -->
    <div class="absolute inset-0 bg-[#f8f9fa]"></div>

    <!-- 底层背景 - 平铺水墨纹理 -->
    <div class="absolute inset-0 bg-center bg-cover opacity-40" :style="{ backgroundImage: `url('${baseUrl}images/optimized_bg_3.png')` }"></div>

    <!-- 装饰层背景 -->
    <div class="absolute inset-0 bg-center bg-cover opacity-60" :style="{ backgroundImage: `url('${baseUrl}images/light_bg_2.png')` }"></div>

    <!-- 主内容容器 -->
    <div class="relative z-10 w-full max-w-[375px] min-h-screen flex flex-col px-4 py-4">

      <!-- 顶部区域 -->
      <div class="mb-5">
        <div class="flex items-center justify-between">
          <div class="w-14"></div>
          <!-- 页面标题 -->
          <h1 class="text-xl font-medium text-[#2c3e50] font-calligraphy title-extra-spacing">寻古问心·照见本真</h1>
          <!-- 简洁进度指示 -->
          <span class="text-sm text-gray-400 tracking-widest">{{ currentIndex + 1 }}/{{ questions.length }}</span>
        </div>

        <!-- 简洁进度条 -->
        <div class="h-1.5 bg-gray-200 rounded-full overflow-hidden mt-4">
          <div
            class="h-full bg-[#2c3e50] rounded-full transition-all duration-500 ease-out"
            :style="{ width: `${(currentIndex + 1) / questions.length * 100}%` }"
          ></div>
        </div>
      </div>

      <!-- 题目卡片区域 - 卡片下移 mt-10 -->
      <div class="flex-1 mt-10">
        <QuestionCard
          v-if="currentQuestion"
          :question="currentQuestion"
          :current-index="currentIndex"
          :selected-option="selectedOptions[currentIndex]"
          @select="handleSelect"
          @goto-question="handleGotoQuestion"
        />
      </div>

      <!-- 导航按钮 -->
      <div class="mt-6">
        <div class="flex justify-between items-center gap-4">
          <!-- 上一题 -->
          <button
            v-if="currentIndex > 0"
            @click="handlePrevious"
            class="flex-1 py-3 rounded-2xl text-base font-medium transition-all font-calligraphy tracking-widest btn-prev"
          >
            上一题
          </button>
          <div v-else class="flex-1"></div>

          <!-- 下一题 -->
          <button
            v-if="selectedOptions[currentIndex] >= 0 && currentIndex < questions.length - 1"
            @click="handleSelect(selectedOptions[currentIndex])"
            class="flex-1 py-3 rounded-2xl text-base font-medium transition-all shadow-md font-calligraphy tracking-widest btn-next"
          >
            下一题
          </button>

          <!-- 完成按钮 -->
          <button
            v-if="isComplete"
            @click="handleRestart"
            class="flex-1 py-3 rounded-2xl text-base font-medium transition-all shadow-md font-calligraphy tracking-widest btn-restart"
          >
            重新开始
          </button>
        </div>
      </div>

      <!-- 题目导航 - 简洁收起式 -->
      <div class="mt-6">
        <details class="group">
          <summary class="cursor-pointer list-none flex items-center justify-between text-sm text-gray-400 hover:text-gray-600 transition-colors tracking-widest">
            <span>题目导航</span>
            <svg class="w-4 h-4 transition-transform group-open:rotate-180" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7"/>
            </svg>
          </summary>
          <div class="mt-4 pt-4 border-t border-gray-200/50">
            <!-- 7×5 网格 -->
            <div class="grid grid-cols-7 gap-2">
              <button
                v-for="(_, index) in questions"
                :key="index"
                @click="handleGotoQuestion(index)"
                class="w-8 h-8 rounded-xl flex items-center justify-center text-xs font-medium transition-all tracking-widest nav-btn"
                :class="[
                  index === currentIndex
                    ? 'bg-[#2c3e50] text-white'
                    : selectedOptions[index] >= 0
                      ? 'bg-emerald-100 text-emerald-700'
                      : 'bg-gray-100 text-gray-400'
                ]"
              >
                {{ index + 1 }}
              </button>
            </div>
          </div>
        </details>
      </div>

      <!-- 底部信息 -->
      <div class="pt-6 pb-2 text-center">
        <p class="text-xs text-gray-300">寻古问心·照见本真 H5原型 v2.9</p>
      </div>
    </div>
  </div>
</template>

