import type { 
  DataSource, DataQuestion, DataOption, DataIdentityType,
  DataSourceV2, IdentityVariant, QuestionV2, OptionV2,
  Question, Option, IdentityInfo, ElementWeights, ElementWeightsCN, ElementType, ElementTypeCN,
  VersionDetectionResult
} from './types'
import { ELEMENT_MAP, ELEMENT_MAP_REVERSE } from './types'

// 导入原始数据
import rawDataV1 from '../data/real_data_v1.1.json'
import rawDataV2 from '../data/real_data_v2.1.json'

/**
 * 检测数据版本
 */
function detectDataSource(data: any): VersionDetectionResult {
  // 检查是否是v2.0格式
  if (data.version && data.version.startsWith('v2')) {
    return {
      version: data.version || 'v2.x',
      data: data as DataSourceV2
    }
  }
  
  // 检查是否是v1.1格式
  if (data.identityTypes && Array.isArray(data.identityTypes)) {
    return {
      version: 'v1.1',
      data: data as DataSource
    }
  }
  
  // 默认假设为v1.1
  return {
    version: 'v1.1',
    data: data as DataSource
  }
}

/**
 * 将中文五行权重转换为英文五行权重
 */
function convertWeightsCNtoEN(cnWeights: ElementWeightsCN): ElementWeights {
  return {
    metal: cnWeights.金 || 0,
    wood: cnWeights.木 || 0,
    water: cnWeights.水 || 0,
    fire: cnWeights.火 || 0,
    earth: cnWeights.土 || 0
  }
}

/**
 * 将数组格式的五行权重转换为英文五行权重
 * 数组顺序: [金,木,水,火,土]
 */
function convertWeightsArrayToEN(weightsArray: number[]): ElementWeights {
  return {
    metal: weightsArray[0] || 0,
    wood: weightsArray[1] || 0,
    water: weightsArray[2] || 0,
    fire: weightsArray[3] || 0,
    earth: weightsArray[4] || 0
  }
}

/**
 * 权重归一化函数
 * v2.1数据所有权重总和为6，无需归一化
 * 保持向后兼容性：总和为5或6时返回原值，其他情况归一化到5
 */
export function normalizeWeights(weights: number[]): number[] {
  if (!weights || weights.length !== 5) {
    return [0, 0, 0, 0, 0]
  }
  
  const sum = weights.reduce((total, weight) => total + weight, 0)
  
  // 如果总和为0，返回原值
  if (sum === 0) {
    return weights
  }
  
  // 如果总和已经是5，无需归一化
  if (sum === 5) {
    return weights
  }
  
  // v2.1数据所有权重总和为6，无需归一化
  if (sum === 6) {
    return weights
  }
  
  // 归一化到总和为5（处理其他情况）
  const normalized = weights.map(weight => (weight / sum) * 5)
  
  // 四舍五入到1位小数
  const rounded = normalized.map(val => Math.round(val * 10) / 10)
  
  // 由于四舍五入可能导致总和不是5，进行调整
  const roundedSum = rounded.reduce((total, weight) => total + weight, 0)
  const diff = 5 - roundedSum
  
  if (Math.abs(diff) > 0.01) {
    // 找到最大值进行调整
    let maxIndex = 0
    let maxValue = 0
    for (let i = 0; i < rounded.length; i++) {
      if (rounded[i] > maxValue) {
        maxValue = rounded[i]
        maxIndex = i
      }
    }
    
    // 调整最大值
    rounded[maxIndex] = Math.round((rounded[maxIndex] + diff) * 10) / 10
  }
  
  return rounded
}

/**
 * 根据五行权重确定主要五行元素
 */
function getDominantElementFromWeights(weights: ElementWeightsCN): ElementType {
  const elements: ElementTypeCN[] = ['金', '木', '水', '火', '土']
  let maxElement: ElementTypeCN = '金'
  let maxWeight = 0
  
  for (const element of elements) {
    if (weights[element] > maxWeight) {
      maxWeight = weights[element]
      maxElement = element
    }
  }
  
  return ELEMENT_MAP[maxElement]
}

/**
 * 根据数组权重确定主要五行元素
 */
function getDominantElementFromArray(weights: number[]): ElementType {
  const elements: ElementTypeCN[] = ['金', '木', '水', '火', '土']
  let maxIndex = 0
  let maxWeight = 0
  
  for (let i = 0; i < weights.length; i++) {
    if (weights[i] > maxWeight) {
      maxWeight = weights[i]
      maxIndex = i
    }
  }
  
  return ELEMENT_MAP[elements[maxIndex]]
}

/**
 * 从v1.1原始数据选项转换为应用内部选项
 */
function convertOptionV1(dataOption: DataOption, questionId: number, optionIndex: number): Option {
  return {
    id: `${questionId}-${optionIndex}`,
    text: dataOption.text,
    element: getDominantElementFromWeights(dataOption.weights),
    weights: convertWeightsCNtoEN(dataOption.weights)
  }
}

/**
 * 从v2.0原始数据选项转换为应用内部选项
 */
function convertOptionV2(dataOption: OptionV2, questionId: number, optionIndex: number): Option {
  // 归一化权重
  const normalizedWeights = normalizeWeights(dataOption.五行权重)
  
  return {
    id: `${questionId}-${optionIndex}`,
    text: dataOption.text,
    element: getDominantElementFromArray(normalizedWeights),
    weights: convertWeightsArrayToEN(normalizedWeights),
    letter: dataOption.letter,
    fourDimensionText: dataOption.四维倾向文本,
    originalText: dataOption.原选项文本
  }
}

/**
 * 从v1.1原始数据身份转换为应用内部身份
 */
function convertIdentityV1(dataIdentity: DataIdentityType): IdentityInfo {
  const code = dataIdentity.code
  
  // 临时五行映射（基于code）
  let element: ElementType = 'metal' // 默认金系
  
  if (code.startsWith('00')) {
    element = 'metal' // 金系
  } else if (code.startsWith('01')) {
    element = 'wood'  // 木系
  } else if (code.startsWith('10')) {
    element = 'water' // 水系
  } else if (code.startsWith('11')) {
    // 根据第三位决定火系或土系
    element = code[2] === '0' ? 'fire' : 'earth'
  }
  
  return {
    code: dataIdentity.code,
    name: dataIdentity.name,
    dimension: dataIdentity.dimension,
    description: dataIdentity.description,
    element: element,
    traits: dataIdentity.personality_traits || []
  }
}

/**
 * 从v2.0原始数据身份转换为应用内部身份
 */
function convertIdentityV2(dataIdentity: IdentityVariant): IdentityInfo {
  return {
    id: dataIdentity.id,
    code: dataIdentity.code,
    name: dataIdentity.name,
    dimension: dataIdentity.category, // v2.0 中 category 对应 v1.1 的 dimension
    description: dataIdentity.core_description,
    element: ELEMENT_MAP[dataIdentity.element],
    traits: dataIdentity.personality_traits || [],
    category: dataIdentity.category,
    category_desc: dataIdentity.category_desc,
    element_desc: dataIdentity.element_desc,
    historical_figures: dataIdentity.historical_figures,
    core_description: dataIdentity.core_description,
    daily_practice: dataIdentity.daily_practice,
    self_cultivation: dataIdentity.self_cultivation,
    image_url: dataIdentity.image_url
  }
}

/**
 * 加载并转换v1.1原始数据
 */
function loadDataV1(data: DataSource): {
  questions: Question[]
  identities: IdentityInfo[]
  metadata: DataSource['metadata']
} {
  // 转换题目数据
  const questions: Question[] = data.questions.map((dataQuestion: DataQuestion, index: number) => ({
    id: index + 1,
    text: dataQuestion.text,
    options: dataQuestion.options.map((option: DataOption, optionIndex: number) => 
      convertOptionV1(option, index + 1, optionIndex)
    )
  }))
  
  // 转换身份数据
  const identities: IdentityInfo[] = data.identityTypes.map((identity: DataIdentityType) => 
    convertIdentityV1(identity)
  )
  
  return {
    questions,
    identities,
    metadata: data.metadata
  }
}

/**
 * 加载并转换v2.0原始数据
 */
function loadDataV2(data: DataSourceV2): {
  questions: Question[]
  identities: IdentityInfo[]
  metadata: {
    version: string
    description: string
    created_at: string
    note: string
  }
} {
  // 转换题目数据
  const questions: Question[] = data.questions.map((dataQuestion: QuestionV2) => ({
    id: dataQuestion.number,
    text: dataQuestion.question,
    title: dataQuestion.title,
    number: dataQuestion.number,
    options: dataQuestion.options.map((option: OptionV2, optionIndex: number) => 
      convertOptionV2(option, dataQuestion.number, optionIndex)
    )
  }))
  
  // 转换身份数据
  const identities: IdentityInfo[] = data.identities.map((identity: IdentityVariant) => 
    convertIdentityV2(identity)
  )
  
  // 转换元数据
  const metadata = {
    version: data.version,
    description: data.description,
    created_at: data.created_at,
    note: data.note
  }
  
  return {
    questions,
    identities,
    metadata
  }
}

/**
 * 加载并转换原始数据（自动检测版本）
 */
export function loadData(): {
  questions: Question[]
  identities: IdentityInfo[]
  metadata: {
    version: string
    description: string
    created_at: string
    note: string
  }
} {
  // 首先尝试加载v2.0数据
  try {
    const v2Detection = detectDataSource(rawDataV2)
    if (v2Detection.version.startsWith('v2')) {
      console.log(`加载 ${v2Detection.version} 数据`)
      return loadDataV2(v2Detection.data as DataSourceV2)
    }
  } catch (error) {
    console.warn('v2.x 数据加载失败，回退到 v1.1', error)
  }
  
  // 回退到v1.1数据
  const v1Detection = detectDataSource(rawDataV1)
  console.log('加载 v1.1 数据')
  return loadDataV1(v1Detection.data as DataSource)
}

/**
 * 直接加载v2.0数据（不进行版本检测）
 */
export function loadDataV2Directly(): {
  questions: Question[]
  identities: IdentityInfo[]
  metadata: {
    version: string
    description: string
    created_at: string
    note: string
  }
} {
  const v2Detection = detectDataSource(rawDataV2)
  if (!v2Detection.version.startsWith('v2')) {
    throw new Error(`数据格式不是v2.x，实际版本: ${v2Detection.version}`)
  }
  return loadDataV2(v2Detection.data as DataSourceV2)
}

/**
 * 直接加载v1.1数据（不进行版本检测）
 */
export function loadDataV1Directly(): {
  questions: Question[]
  identities: IdentityInfo[]
  metadata: DataSource['metadata']
} {
  const v1Detection = detectDataSource(rawDataV1)
  if (v1Detection.version !== 'v1.1') {
    throw new Error('数据格式不是v1.1')
  }
  return loadDataV1(v1Detection.data as DataSource)
}

/**
 * 获取数据版本信息
 */
export function getDataVersion(): string {
  try {
    const v2Detection = detectDataSource(rawDataV2)
    if (v2Detection.version.startsWith('v2')) {
      return (rawDataV2 as any).version || v2Detection.version
    }
  } catch (error) {
    // 忽略错误
  }
  
  return (rawDataV1 as any).metadata?.version || 'v1.1'
}

/**
 * 获取五行颜色（Tailwind颜色类）
 */
export function getElementColor(element: ElementType): string {
  const colorMap: Record<ElementType, string> = {
    metal: 'bg-metal text-white',
    wood: 'bg-wood text-white',
    water: 'bg-water text-white',
    fire: 'bg-fire text-white',
    earth: 'bg-earth text-white'
  }
  return colorMap[element] || 'bg-gray-500 text-white'
}

/**
 * 获取五行中文名称
 */
export function getElementNameCN(element: ElementType): string {
  return ELEMENT_MAP_REVERSE[element]
}

/**
 * 获取五行图标或符号（临时使用文字）
 */
export function getElementSymbol(element: ElementType): string {
  const symbolMap: Record<ElementType, string> = {
    metal: '⚔️',
    wood: '🌳',
    water: '💧',
    fire: '🔥',
    earth: '⛰️'
  }
  return symbolMap[element] || '✨'
}